// ============================================
// ROLLBACK ENGINE
// ============================================
// For each bid change snapshot:
// 1. Compare current metrics vs snapshot baseline
// 2. If metrics got WORSE (CTR dropped >30%, or CPL increased >20%):
//    -> ROLLBACK: restore the old bid
// 3. If metrics improved or stable -> mark snapshot as checked (no rollback needed)

const snapshots = $('Fetch Rollback Candidates').all().map(i => i.json);
const statsData = $('Fetch Current Stats').first().json;
const crmItems = $('Fetch CRM Leads').all().map(i => i.json);

if (snapshots.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No rollback candidates' } }];
}

// Parse stats
const statsArr = statsData?.data?.result?.data || statsData?.data || (Array.isArray(statsData) ? statsData : []);
const statsMap = {};
if (Array.isArray(statsArr)) {
  statsArr.forEach(s => {
    const adId = Number(s.ad_id);
    const spend = Number(s.money) || 0;
    const clicks = Number(s.clicks_count) || 0;
    const shows = Number(s.shows_count) || 0;
    statsMap[adId] = {
      spend, clicks, shows,
      ctr: shows > 0 ? (clicks / shows * 100) : 0,
      cpc: clicks > 0 ? spend / clicks : 0
    };
  });
}

// CRM map
const crmMap = {};
crmItems.forEach(c => {
  const adId = Number(c.ad_id);
  crmMap[adId] = { leads: Number(c.total_leads) || 0, deps: Number(c.depositors) || 0 };
});

const actions = [];

snapshots.forEach(snap => {
  const adId = Number(snap.ad_id);
  const stats = statsMap[adId];
  const crm = crmMap[adId] || { leads: 0, deps: 0 };
  const snapshotCpl = Number(snap.snapshot_cpl) || 0;
  const snapshotCtr = Number(snap.snapshot_ctr) || 0;

  let shouldRollback = false;
  let reason = '';

  if (!stats || stats.clicks < 5) {
    // Not enough data to evaluate, mark as checked
    actions.push({
      json: {
        snapshot_id: snap.snapshot_id,
        ad_id: adId,
        action: 'MARK_CHECKED',
        reason: 'Insufficient data for evaluation',
        rollback_bid: snap.snapshot_bid
      }
    });
    return;
  }

  const currentCpl = crm.leads > 0 ? stats.spend / crm.leads : (stats.spend > 50 ? 99999 : 0);
  const currentCtr = stats.ctr;

  // Check CTR deterioration (>30% drop)
  if (snapshotCtr > 0 && currentCtr > 0 && currentCtr < snapshotCtr * 0.7) {
    shouldRollback = true;
    reason = `CTR dropped ${((1 - currentCtr / snapshotCtr) * 100).toFixed(0)}%: ${snapshotCtr.toFixed(2)}% -> ${currentCtr.toFixed(2)}%`;
  }

  // Check CPL deterioration (>20% increase)
  if (snapshotCpl > 0 && currentCpl > 0 && currentCpl !== 99999 && currentCpl > snapshotCpl * 1.2) {
    shouldRollback = true;
    reason = `CPL increased ${((currentCpl / snapshotCpl - 1) * 100).toFixed(0)}%: $${snapshotCpl.toFixed(0)} -> $${currentCpl.toFixed(0)}`;
  }

  // Had leads before, now zero with significant spend
  if (snapshotCpl > 0 && snapshotCpl < 99999 && crm.leads === 0 && stats.spend > 100) {
    shouldRollback = true;
    reason = `Lost leads: had CPL $${snapshotCpl.toFixed(0)}, now 0 leads with $${stats.spend.toFixed(0)} spend`;
  }

  if (shouldRollback) {
    actions.push({
      json: {
        snapshot_id: snap.snapshot_id,
        ad_id: adId,
        action: 'ROLLBACK',
        rollback_bid: snap.snapshot_bid,
        current_cpl: currentCpl === 99999 ? -1 : Math.round(currentCpl * 100) / 100,
        snapshot_cpl: snapshotCpl,
        current_ctr: Math.round(currentCtr * 10000) / 10000,
        snapshot_ctr: snapshotCtr,
        reason: reason
      }
    });
  } else {
    actions.push({
      json: {
        snapshot_id: snap.snapshot_id,
        ad_id: adId,
        action: 'MARK_CHECKED',
        reason: 'Metrics stable or improved',
        rollback_bid: snap.snapshot_bid
      }
    });
  }
});

if (actions.length === 0) {
  return [{ json: { action: 'NONE', reason: 'All snapshots evaluated, no actions needed' } }];
}

return actions;

const items = $input.all();
const rollbacks = items.filter(i => i.json.action === 'ROLLBACK');
const checked = items.filter(i => i.json.action === 'MARK_CHECKED');
const total = items.filter(i => i.json.action && i.json.action !== 'NONE');

if (rollbacks.length === 0 && total.length === 0) return [];

let msg = `ROLLBACK ENGINE ${$now.toFormat('dd.MM.yyyy HH:mm')}\n`;
msg += `Checked: ${total.length} | Rollbacks: ${rollbacks.length} | OK: ${checked.length}\n`;

if (rollbacks.length > 0) {
  msg += `\nROLLBACKS:\n`;
  rollbacks.forEach(r => {
    msg += `  #${r.json.ad_id}: bid -> $${r.json.rollback_bid} | ${r.json.reason}\n`;
  });
}

return [{ json: { message: msg, has_rollbacks: rollbacks.length > 0 } }];
